1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PREMIUM = 60;
19	
20	const groupCountsByType = (items: Item[]): Map<string, number> => {
21	  const counts = new Map<string, number>();
22	  for (const { type } of items) {
23	    counts.set(type, (counts.get(type) ?? 0) + 1);
24	  }
25	  return counts;
26	};
27	
28	const basePremiumForGroup = (type: string, count: number): number => {
29	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
30	  return count * BASE_PREMIUM[type];
31	};
32	
33	const basePremiumFor = (items: Item[]): number => {
34	  let total = 0;
35	  for (const [type, count] of groupCountsByType(items)) {
36	    total += basePremiumForGroup(type, count);
37	  }
38	  return total;
39	};
40	
41	const premiumFor = (items: Item[]): number => {
42	  const basePremium = basePremiumFor(items);
43	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
44	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
45	};
46	
47	type QuoteResult = { premium: number };
48	type ScenarioOutput = { results: QuoteResult[] };
49	
50	const quoteStep = ({ items }: Step): QuoteResult => ({
51	  premium: premiumFor(items),
52	});
53	
54	export const runScenario = (input: Scenario): ScenarioOutput => ({
55	  results: input.steps.map(quoteStep),
56	});
